// build-store-profile — Read Upstream Artifacts
// Reads shopify-import.json and retrieves intake payload from input.
//
// SELF-HOSTED: Reads shopify-import.json from disk.
//
// CLOUD MODE: n8n Cloud does not allow require('fs'). When fs is unavailable,
//             shopify_import is read from the trigger input payload instead of
//             from disk. The orchestrator's Prepare Profile Input node must pass
//             shopify_import inline when cloud_mode is active.

// Cloud-mode detection — n8n Cloud does not allow require('fs')
let fs, path;
let cloudMode = false;
try {
  fs   = require('fs');
  path = require('path');
} catch (_e) {
  cloudMode = true;
}

const input             = $input.first().json;
const runtimeConfig     = input.runtime_config;
const intakePayload     = input.normalized_intake_payload;
const projectId         = input.project_id;

if (!runtimeConfig || !intakePayload || !projectId) {
  throw new Error(
    'MISSING_RUNTIME_CONFIG: build-store-profile requires runtime_config, normalized_intake_payload, and project_id'
  );
}

// ── Validate intake fields required by this workflow ─────────────────────
const intakeRequired = ['project_id', 'primary_market', 'primary_language', 'primary_currency', 'vertical', 'price_positioning'];
const intakeMissing  = intakeRequired.filter((f) => !intakePayload[f]);
if (intakeMissing.length > 0) {
  throw new Error(`MISSING_ARTIFACT: intake_payload is missing required fields: ${intakeMissing.join(', ')}`);
}

let shopifyImport;

if (cloudMode) {
  // CLOUD: Read shopify_import from the trigger input payload.
  // The orchestrator must have passed it through from import-shopify-data output.
  shopifyImport = input.shopify_import;
  if (!shopifyImport) {
    throw new Error(
      'CLOUD_MODE_ERROR: shopify_import not found in trigger input. ' +
      'In cloud mode, the orchestrator must pass shopify_import inline from import-shopify-data output. ' +
      'Check that Prepare Profile Input in orchestrate-phase1 includes shopify_import.'
    );
  }
  console.warn(
    `CLOUD_MODE: build-store-profile reading shopify_import from n8n input payload (no disk) for project: ${projectId}`
  );
} else {
  // SELF-HOSTED: Read from disk
  const projectRoot       = runtimeConfig.project_root;
  const shopifyImportPath = path.join(projectRoot, projectId, 'shopify-import.json');

  if (!fs.existsSync(shopifyImportPath)) {
    throw new Error(`MISSING_ARTIFACT: shopify-import.json not found at ${shopifyImportPath}`);
  }

  try {
    shopifyImport = JSON.parse(fs.readFileSync(shopifyImportPath, 'utf8'));
  } catch (err) {
    throw new Error(`PARSE_ERROR: Failed to parse shopify-import.json: ${err.message}`);
  }
}

// ── project_id consistency check ──────────────────────────────────────────
if (shopifyImport.project_id !== projectId) {
  throw new Error(
    `PROJECT_ID_MISMATCH: shopify-import project_id "${shopifyImport.project_id}" does not match runtime project_id "${projectId}"`
  );
}

// ── Validate shopify-import has required data ─────────────────────────────
const rawShopData    = shopifyImport.raw_shop_data || {};
const importSummary  = shopifyImport.import_summary || {};

if (!rawShopData.shop_name) {
  throw new Error('MISSING_ARTIFACT: shopify-import raw_shop_data.shop_name is empty');
}
if (!rawShopData.shop_domain) {
  throw new Error('MISSING_ARTIFACT: shopify-import raw_shop_data.shop_domain is empty');
}

return [{
  json: {
    project_id:      projectId,
    runtime_config:  runtimeConfig,
    intake_payload:  intakePayload,
    shopify_import:  shopifyImport,
    raw_shop_data:   rawShopData,
    import_summary:  importSummary,
    cloud_mode:      cloudMode,
  },
}];

// build-store-profile — Map Fields, Validate, and Write
// Maps intake + Shopify data to store-profile schema fields.
// Derives catalog_type from active product count.
// Adds runtime envelope for observability.
//
// SELF-HOSTED: Validates against schemas/store-profile.schema.json via AJV.
//              Writes store-profile.json atomically. Quarantines on failure.
//
// CLOUD MODE: n8n Cloud does not allow require('fs'). When fs is unavailable,
//             AJV schema validation and all filesystem writes are skipped.
//             The assembled store_profile object is returned inline.
//             cloud_mode: true and cloud_warnings are set in output.
//             No persistence, no schema validation in cloud mode.
//
// NOTE: This is a temporary cloud-safe fallback for smoke testing.
//       Production cloud execution requires a real persistence + validation layer.

// ── buildRunId helper (no crypto needed) ─────────────────────────────────
function buildRunId() {
  const ts = new Date().toISOString().replace(/[-:T.Z]/g, '').slice(0, 14);
  const rand = Math.random().toString(36).slice(2, 6);
  return 'run-' + ts + '-' + rand;
}

// Cloud-mode detection — n8n Cloud does not allow require('fs')
let fs, path;
let cloudMode = false;
try {
  fs   = require('fs');
  path = require('path');
} catch (_e) {
  cloudMode = true;
}
// Also check if cloudMode was set upstream
if (!cloudMode && $input.first().json.cloud_mode) {
  cloudMode = true;
}

const input          = $input.first().json;
const intakePayload  = input.intake_payload;
const rawShopData    = input.raw_shop_data;
const importSummary  = input.import_summary;
const runtimeConfig  = input.runtime_config;
const projectId      = input.project_id;
const projectRoot    = cloudMode ? null : runtimeConfig.project_root;

// ── Derive catalog_type from active product count ─────────────────────────
const activeCount = typeof importSummary.active_product_count === 'number'
  ? importSummary.active_product_count
  : 0;

let catalogType;
if (activeCount === 0) {
  catalogType = 'small-curated-catalog'; // provisional — no products yet
} else if (activeCount === 1) {
  catalogType = 'single-product';
} else if (activeCount <= 15) {
  catalogType = 'small-curated-catalog';
} else if (activeCount <= 200) {
  catalogType = 'broad-catalog';
} else {
  catalogType = 'mixed-catalog';
}

// ── Map publish_mode → operating_mode ────────────────────────────────────
const OPERATING_MODE_MAP = {
  'no-publish':       'draft-first',
  'draft-only':       'draft-first',
  'draft-and-review': 'staging-first',
};
const operatingMode = OPERATING_MODE_MAP[intakePayload.publish_mode] || 'draft-first';

// ── New optional enrichments ──────────────────────────────────────────────

// Assortment shape heuristic
let assortmentShape = 'unknown';
if (activeCount === 1) assortmentShape = 'single-hero-product';
else if (activeCount <= 5) assortmentShape = 'tight-specialist-range';
else if (activeCount <= 50) assortmentShape = 'curated-multi-category';
else if (activeCount <= 500) assortmentShape = 'broad-generalist';
else assortmentShape = 'broad-generalist';

// UX maturity heuristic (from brand_maturity + catalog_type)
const uxMaturityMap = { new: 'minimal', growing: 'basic', established: 'intermediate', legacy: 'advanced' };
const uxMerchandisingMaturity = uxMaturityMap['new'] || 'unknown'; // brand_maturity defaults to 'new'

// Open questions (explicit unknowns)
const openQuestions = [];
if (activeCount === 0) openQuestions.push('No active products found — catalog_type and assortment_shape are provisional until products exist');
if (!intakePayload.competitor_urls || intakePayload.competitor_urls.length === 0) openQuestions.push('No competitor URLs provided — competitive context will be archetype-only');
if (!intakePayload.must_feel_like && !intakePayload.brand_role) openQuestions.push('No brand direction signals in intake — brand_voice_hint is inferred from store_type and price_positioning only');

// Brand voice hint heuristic
const brandVoiceMap = {
  'premium': 'premium-confident', 'luxury': 'premium-confident',
  'mass-premium': 'lifestyle-friendly', 'mass-market': 'value-pragmatic',
  'budget': 'budget-pragmatic', 'to-be-defined': 'unknown'
};
const brandVoiceHint = brandVoiceMap[intakePayload.price_positioning] || 'unknown';

// Value proposition hint (short, derived)
const valuePropHint = intakePayload.vertical
  ? `${intakePayload.store_type || 'store'} in ${intakePayload.vertical} for ${intakePayload.primary_market} market at ${intakePayload.price_positioning || 'unspecified'} price point`
  : null;

// Target audience hypothesis (single, rough)
const targetAudienceHypotheses = [{
  segment_label: 'Primary Segment (hypothesis)',
  description: `Shoppers in the ${intakePayload.vertical || 'general'} vertical, ${intakePayload.primary_market} market, ${intakePayload.price_positioning || 'unknown'} price sensitivity`,
  confidence: 'low',
  source_signals: ['intake.vertical', 'intake.primary_market', 'intake.price_positioning']
}];

// ── Assemble store-profile ─────────────────────────────────────────────────
const storeProfile = {
  store_id:         projectId,
  store_name:       rawShopData.shop_name,
  store_type:       intakePayload.store_type       || 'multi-product-store',
  platform:         'shopify',
  business_model:   intakePayload.business_model   || 'ecommerce',
  primary_market:   intakePayload.primary_market,
  target_markets:   intakePayload.target_markets   || [intakePayload.primary_market],
  primary_language: intakePayload.primary_language,
  languages:        intakePayload.languages        || [intakePayload.primary_language],
  primary_currency: intakePayload.primary_currency,
  currencies:       intakePayload.currencies       || [intakePayload.primary_currency],
  vertical:         intakePayload.vertical,
  price_positioning:intakePayload.price_positioning,
  catalog_type:     catalogType,
  brand_maturity:   'new',
  operating_mode:   operatingMode,
  domain:           rawShopData.shop_domain,
  // NEW optional enrichments
  assortment_shape: assortmentShape,
  target_audience_hypotheses: targetAudienceHypotheses,
  brand_voice_hint: brandVoiceHint,
  ux_merchandising_maturity: uxMerchandisingMaturity,
};

// Add optional fields only if they have values
if (valuePropHint) storeProfile.value_proposition_hint = valuePropHint;
if (openQuestions.length > 0) storeProfile.open_questions = openQuestions;
if (intakePayload.special_notes) storeProfile.notes = intakePayload.special_notes;

// Clean undefined values
Object.keys(storeProfile).forEach(k => storeProfile[k] === undefined && delete storeProfile[k]);

// ── Build runtime envelope ────────────────────────────────────────────────
const runId = buildRunId();
const executionTs = new Date().toISOString();

if (cloudMode) {
  // CLOUD SKIP: No local schema file or AJV available. No filesystem write.
  // Return assembled store_profile inline without validation or persistence.
  console.warn(
    `CLOUD_MODE: build-store-profile skipping AJV schema validation and artifact write for project: ${projectId}. ` +
    'store_profile returned inline without schema validation.'
  );

  const envelope = {
    runtime: {
      run_id: runId,
      phase_id: 'build-store-profile',
      execution_ts: executionTs,
      cloud_mode: true,
      env: 'cloud-smoke',
      schema_version: '1.0'
    },
    store: {
      project_id: projectId,
      artifact_name: 'store-profile',
      artifact_path: null
    },
    status: {
      code: 'SUCCESS',
      completed_at: executionTs,
      fatal_errors: [],
      warnings: [
        'AJV schema validation skipped — cloud mode',
        'Artifact write skipped — cloud mode'
      ],
      retryable: false
    },
    diagnostics: {
      input_summary: {
        project_id: projectId,
        vertical: intakePayload.vertical,
        price_positioning: intakePayload.price_positioning,
        primary_market: intakePayload.primary_market,
        active_products: activeCount,
        catalog_context: 'shopify-derived'
      },
      output_summary: {
        store_type: storeProfile.store_type,
        catalog_type: catalogType,
        assortment_shape: assortmentShape,
        ux_merchandising_maturity: uxMerchandisingMaturity,
        open_questions_count: openQuestions.length
      },
      validation: {
        schema_ref: 'schemas/store-profile.schema.json',
        result: 'SKIPPED',
        errors: [],
        warnings: ['Validation skipped — cloud mode']
      },
      lineage: {
        upstream_phases: ['resolve-runtime-config', 'intake-store-input', 'import-shopify-data'],
        upstream_artifacts: ['normalized_intake_payload', 'shopify-import']
      },
      missing_data: openQuestions.map(q => ({ field: 'various', reason: q, impact: 'degraded-output' }))
    }
  };

  return [{
    json: {
      project_id:    projectId,
      artifact_path: null,
      artifact_name: 'store-profile',
      store_profile: storeProfile,
      runtime_config:runtimeConfig,
      status:        'SUCCESS',
      cloud_mode:    true,
      cloud_warnings: [
        'AJV schema validation skipped — no schema files accessible in n8n Cloud',
        'Artifact write skipped — no filesystem in n8n Cloud',
        'Checkpoint update skipped — no filesystem in n8n Cloud',
      ],
      notes: [
        activeCount === 0
          ? 'WARNING: No active products found in Shopify import. catalog_type defaulted to small-curated-catalog.'
          : null,
        importSummary.pagination_note || null,
      ].filter(Boolean),
      envelope: envelope,
    },
  }];
}

// ── SELF-HOSTED: AJV schema validation ───────────────────────────────────
const schemaPath = path.join(runtimeConfig.ajv_schema_path, 'store-profile.schema.json');

if (!fs.existsSync(schemaPath)) {
  throw new Error(`SCHEMA_LOAD_ERROR: store-profile.schema.json not found at ${schemaPath}`);
}

const schema = JSON.parse(fs.readFileSync(schemaPath, 'utf8'));

let AjvClass;
try {
  AjvClass = require('ajv/dist/2020');
} catch {
  try {
    AjvClass = require('ajv');
  } catch (err) {
    throw new Error(
      `SCHEMA_LOAD_ERROR: AJV not available in n8n environment: ${err.message}. ` +
      'Install ajv@8 in the n8n node_modules directory.'
    );
  }
}

const ajv      = new AjvClass({ allErrors: true, strict: false });
const validate = ajv.compile(schema);
const valid    = validate(storeProfile);

if (!valid) {
  // ── Quarantine rejected artifact ────────────────────────────────────────
  const quarantineDir = path.join(projectRoot, projectId, '.runtime', 'quarantine');
  fs.mkdirSync(quarantineDir, { recursive: true });
  const ts           = new Date().toISOString().replace(/[:.]/g, '-');
  const quarantinePath = path.join(quarantineDir, `store-profile.${ts}.rejected.json`);
  const quarantinePayload = {
    quarantine_reason: 'SCHEMA_VIOLATION',
    artifact_name:     'store-profile',
    workflow_id:       'build-store-profile',
    validation_errors: validate.errors,
    timestamp:         new Date().toISOString(),
    project_id:        projectId,
    artifact_payload:  storeProfile,
  };
  fs.writeFileSync(quarantinePath, JSON.stringify(quarantinePayload, null, 2), 'utf8');

  const errorSummary = (validate.errors || [])
    .map((e) => `${e.instancePath || '(root)'} ${e.message}`)
    .join('; ');
  throw new Error(
    `SCHEMA_VIOLATION: store-profile failed validation. Quarantined to ${quarantinePath}. ` +
    `Errors: ${errorSummary}`
  );
}

// ── Atomic write ──────────────────────────────────────────────────────────
const projectDir  = path.join(projectRoot, projectId);
const finalPath   = path.join(projectDir, 'store-profile.json');
const tmpPath     = path.join(projectDir, 'store-profile.tmp.json');

fs.mkdirSync(projectDir, { recursive: true });
fs.writeFileSync(tmpPath, JSON.stringify(storeProfile, null, 2), 'utf8');
fs.renameSync(tmpPath, finalPath);

// ── Update checkpoint ─────────────────────────────────────────────────────
const checkpointPath = path.join(projectRoot, projectId, '.runtime', 'checkpoint.json');
const now = new Date().toISOString();
try {
  const checkpoint = JSON.parse(fs.readFileSync(checkpointPath, 'utf8'));
  checkpoint.completed_workflows.push({
    workflow_id:     'build-store-profile',
    completed_at:    now,
    output_artifact: 'store-profile.json',
    status:          'SUCCESS',
  });
  checkpoint.last_updated_timestamp = now;
  checkpoint.next_workflow          = 'build-market-intelligence';
  const cpTmp = checkpointPath + '.tmp';
  fs.writeFileSync(cpTmp, JSON.stringify(checkpoint, null, 2), 'utf8');
  fs.renameSync(cpTmp, checkpointPath);
} catch { /* checkpoint update failure is non-fatal in Phase 12 — log it but don't halt */ }

// ── Append to execution log ───────────────────────────────────────────────
const logPath = path.join(projectRoot, projectId, '.runtime', 'execution-log.json');
try {
  const logData = fs.existsSync(logPath)
    ? JSON.parse(fs.readFileSync(logPath, 'utf8'))
    : { entries: [] };
  logData.entries.push({
    timestamp:        now,
    execution_run_id: runId,
    level:            'INFO',
    event_type:       'ARTIFACT_WRITE',
    workflow_id:      'build-store-profile',
    artifact:         'store-profile.json',
    message:          `store-profile.json written. catalog_type=${catalogType}, active_products=${activeCount}`,
  });
  const logTmp = logPath + '.tmp';
  fs.writeFileSync(logTmp, JSON.stringify(logData, null, 2), 'utf8');
  fs.renameSync(logTmp, logPath);
} catch { /* log write failure is non-fatal */ }

// ── Build envelope (self-hosted) ──────────────────────────────────────────
const envelope = {
  runtime: {
    run_id: runId,
    phase_id: 'build-store-profile',
    execution_ts: executionTs,
    cloud_mode: false,
    env: runtimeConfig.env || 'dev',
    schema_version: '1.0'
  },
  store: {
    project_id: projectId,
    artifact_name: 'store-profile',
    artifact_path: finalPath
  },
  status: {
    code: 'SUCCESS',
    completed_at: executionTs,
    fatal_errors: [],
    warnings: [],
    retryable: false
  },
  diagnostics: {
    input_summary: {
      project_id: projectId,
      vertical: intakePayload.vertical,
      price_positioning: intakePayload.price_positioning,
      primary_market: intakePayload.primary_market,
      active_products: activeCount,
      catalog_context: 'shopify-derived'
    },
    output_summary: {
      store_type: storeProfile.store_type,
      catalog_type: catalogType,
      assortment_shape: assortmentShape,
      ux_merchandising_maturity: uxMerchandisingMaturity,
      open_questions_count: openQuestions.length
    },
    validation: {
      schema_ref: 'schemas/store-profile.schema.json',
      result: 'PASS',
      errors: [],
      warnings: []
    },
    lineage: {
      upstream_phases: ['resolve-runtime-config', 'intake-store-input', 'import-shopify-data'],
      upstream_artifacts: ['normalized_intake_payload', 'shopify-import']
    },
    missing_data: openQuestions.map(q => ({ field: 'various', reason: q, impact: 'degraded-output' }))
  }
};

return [{
  json: {
    project_id:    projectId,
    artifact_path: finalPath,
    artifact_name: 'store-profile',
    store_profile: storeProfile,
    runtime_config:runtimeConfig,
    status:        'SUCCESS',
    notes: [
      activeCount === 0
        ? 'WARNING: No active products found in Shopify import. catalog_type defaulted to small-curated-catalog.'
        : null,
      importSummary.pagination_note || null,
    ].filter(Boolean),
    envelope: envelope,
  },
}];
